import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface EngagementTrend {
  day: string;
  engagement: number;
}

interface CommunityData {
  community: {
    activeMembers: number;
    postsToday: number;
  };
  engagementTrend: EngagementTrend[];
  trendLine: number[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const data = response.data as CommunityData;
  const meta = response.meta as MetaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: meta.theme === 'light' ? '#FFFFFF' : '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: meta.primaryColor }}>
              Community Metrics
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Active Members: {data.community.activeMembers}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Posts Today: {data.community.postsToday}
            </Typography>
          </Box>

          <LineChart
            height={120}
            series={[
              {
                data: data.trendLine,
                color: meta.accentColor,
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: data.engagementTrend.map((trend) => trend.day), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
